create table dirkspzm32.isi_order_reord_h (
    sid               varchar2(2 char) not null enable,
    firma_nr          number(*, 0) not null enable,
    reord_id          number(*, 0) not null enable,
    scan_string       varchar2(255 char) not null enable,
    created_date      date not null enable,
    created_login_id  number(*, 0) not null enable,
    modified_date     date not null enable,
    modified_login_id number(*, 0) not null enable,
    lam_bh_id         number(*, 0),
    lam_id            number(*, 0),
    lhm_id            varchar2(20 char),
    lte_id            varchar2(20 char),
    vorgang_id        number(*, 0),
    auf_id            number(*, 0),
    order_action      varchar2(10 char) not null enable,
    reord_menge       number(*, 3) default 0 not null enable
);

alter table dirkspzm32.isi_order_reord_h
    add constraint pk_isi_order_reord_h
        primary key ( reord_id,
                      firma_nr,
                      sid )
            using index enable;


